   481→type regularBucketIterator struct {
   482→	baseBucketIterator[uint64, int64]
   483→}
   484→
   485→func newRegularBucketIterator(spans []Span, buckets []int64, schema int32, positive bool, customValues []float64) regularBucketIterator {
   486→	i := baseBucketIterator[uint64, int64]{
   487→		schema:       schema,
   488→		spans:        spans,
   489→		buckets:      buckets,
   490→		positive:     positive,
   491→		customValues: customValues,
   492→	}
   493→	return regularBucketIterator{i}
   494→}
   495→
   496→func (r *regularBucketIterator) Next() bool {
   497→	if r.spansIdx >= len(r.spans) {
   498→		return false
   499→	}
   500→	span := r.spans[r.spansIdx]
   501→	// Seed currIdx for the first bucket.
   502→	if r.bucketsIdx == 0 {
   503→		r.currIdx = span.Offset
   504→	} else {
   505→		r.currIdx++
   506→	}
   507→	for r.idxInSpan >= span.Length {
   508→		// We have exhausted the current span and have to find a new
   509→		// one. We'll even handle pathologic spans of length 0.
   510→		r.idxInSpan = 0
   511→		r.spansIdx++
   512→		if r.spansIdx >= len(r.spans) {
   513→			return false
   514→		}
   515→		span = r.spans[r.spansIdx]
   516→		r.currIdx += span.Offset
   517→	}
   518→
   519→	// This protects against index out of range panic, which
   520→	// can only happen with an invalid histogram.
   521→	if r.bucketsIdx >= len(r.buckets) {
   522→		return false
   523→	}
   524→	r.currCount += r.buckets[r.bucketsIdx]
   525→	r.idxInSpan++
   526→	r.bucketsIdx++
   527→	return true
   528→}
